<?php
 namespace League\CommonMark\Reference; use League\CommonMark\Normalizer\TextNormalizer; final class Reference implements ReferenceInterface { protected $label; protected $destination; protected $title; public function __construct(string $label, string $destination, string $title) { $this->label = $label; $this->destination = $destination; $this->title = $title; } public function getLabel(): string { return $this->label; } public function getDestination(): string { return $this->destination; } public function getTitle(): string { return $this->title; } public static function normalizeReference(string $string): string { @trigger_error(sprintf('%s::normlizeReference() is deprecated; use %s::normalize() instead', self::class, TextNormalizer::class), E_USER_DEPRECATED); return (new TextNormalizer())->normalize($string); } } 